15	pub fn input_char(s: &mut InputState, c: char) {
16	    clear_selection(s);
17	    let line = &mut s.lines[s.cursor_line];
18	    let byte_idx = char_to_byte_idx(line, s.cursor_col);
19	    line.insert(byte_idx, c);
20	    s.cursor_col += 1;
21	}
