23	pub fn input_backspace(s: &mut InputState) {
24	    if let Some(sel) = s.selection.take() {
25	        s.selection_anchor = None;
26	        delete_selection(s, &sel);
27	        return;
28	    }
29	    if s.cursor_col > 0 {
30	        let line = &mut s.lines[s.cursor_line];
31	        let byte_idx = char_to_byte_idx(line, s.cursor_col);
32	        let prev = prev_char_boundary(line, byte_idx);
33	        line.drain(prev..byte_idx);
34	        s.cursor_col -= 1;
35	    } else if s.cursor_line > 0 {
36	        let removed = s.lines.remove(s.cursor_line);
37	        s.cursor_line -= 1;
38	        let prev_len = s.lines[s.cursor_line].chars().count();
39	        s.lines[s.cursor_line].push_str(&removed);
40	        s.cursor_col = prev_len;
41	    }
42	}
