44	pub fn input_newline(s: &mut InputState) {
45	    clear_selection(s);
46	    let line = s.lines[s.cursor_line].clone();
47	    let byte_idx = char_to_byte_idx(&line, s.cursor_col);
48	    let rest = line[byte_idx..].to_string();
49	    s.lines[s.cursor_line].truncate(byte_idx);
50	    s.cursor_line += 1;
51	    s.lines.insert(s.cursor_line, rest);
52	    s.cursor_col = 0;
53	}
