55	pub fn input_delete_word_left(s: &mut InputState) {
56	    let col = s.cursor_col;
57	    if col == 0 {
58	        return input_backspace(s);
59	    }
60	    let chars: Vec<char> = s.lines[s.cursor_line].chars().collect();
61	    let mut i = col;
62	    while i > 0 && chars[i - 1] == ' ' {
63	        i -= 1;
64	    }
65	    while i > 0 && chars[i - 1] != ' ' {
66	        i -= 1;
67	    }
68	    let line = &mut s.lines[s.cursor_line];
69	    let b_start = char_to_byte_idx(line, i);
70	    let b_end = char_to_byte_idx(line, col);
71	    line.drain(b_start..b_end);
72	    s.cursor_col = i;
73	}
