75	pub fn input_delete_word_right(s: &mut InputState) {
76	    let col = s.cursor_col;
77	    let chars: Vec<char> = s.lines[s.cursor_line].chars().collect();
78	    let mut i = col;
79	    while i < chars.len() && chars[i] == ' ' {
80	        i += 1;
81	    }
82	    while i < chars.len() && chars[i] != ' ' {
83	        i += 1;
84	    }
85	    let line = &mut s.lines[s.cursor_line];
86	    let b_start = char_to_byte_idx(line, col);
87	    let b_end = char_to_byte_idx(line, i);
88	    line.drain(b_start..b_end);
89	}
