91	pub fn input_delete_line(s: &mut InputState) {
92	    let col = s.cursor_col;
93	    if col == 0 {
94	        if s.cursor_line > 0 {
95	            s.lines.remove(s.cursor_line);
96	            s.cursor_line -= 1;
97	            s.cursor_col = s.lines[s.cursor_line].chars().count();
98	        }
99	        return;
100	    }
101	    let line = &mut s.lines[s.cursor_line];
102	    let byte_idx = char_to_byte_idx(line, col);
103	    line.drain(..byte_idx);
104	    s.cursor_col = 0;
105	}
