188	/// Set anchor if not set, move cursor, update selection.
189	/// Selection bounds are stored to match the visually highlighted region:
190	/// - Right (anchor <= cursor): [anchor, cursor) — anchor char included, cursor char excluded
191	/// - Left  (cursor < anchor):  [cursor+1, anchor+1) — current char included, cursor char excluded
192	fn extend_selection(s: &mut InputState, move_fn: fn(&mut InputState)) {
193	    if s.selection_anchor.is_none() {
194	        s.selection_anchor = Some((s.cursor_line, s.cursor_col));
195	    }
196	    let anchor = s.selection_anchor;
197	    move_fn(s); // clears selection_anchor, restore after
198	    s.selection_anchor = anchor;
199	    if let Some(anchor_pt) = s.selection_anchor {
200	        let cursor = (s.cursor_line, s.cursor_col);
201	        if anchor_pt == cursor {
202	            s.selection = None;
203	            s.selection_anchor = None;
204	        } else if cursor < anchor_pt {
205	            // Left-extending: visually highlight (cursor, anchor] = [cursor+1, anchor+1)
206	            let start = advance_pos(&s.lines, cursor.0, cursor.1);
207	            let end   = advance_pos(&s.lines, anchor_pt.0, anchor_pt.1);
208	            s.selection = Some(crate::state::Selection {
209	                start_line: start.0, start_col: start.1,
210	                end_line:   end.0,   end_col:   end.1,
211	            });
212	        } else {
213	            // Right-extending: visually highlight [anchor, cursor)
214	            s.selection = Some(crate::state::Selection {
215	                start_line: anchor_pt.0, start_col: anchor_pt.1,
216	                end_line:   cursor.0,   end_col:   cursor.1,
217	            });
218	        }
219	    }
220	}
