307	fn prev_char_boundary(s: &str, byte_idx: usize) -> usize {
308	    let mut i = byte_idx.saturating_sub(1);
309	    while i > 0 && !s.is_char_boundary(i) {
310	        i -= 1;
311	    }
312	    i
313	}
