315	/// Compute (line_idx, col_idx) from a mouse click at (col, row) inside the input inner area.
316	pub fn cursor_from_mouse(state: &InputState, area: ratatui::layout::Rect, col: u16, row: u16) -> (usize, usize) {
317	    // Inner area starts 1 col in (for border), and first col is ">" prefix (2 chars)
318	    let prefix_w = 2usize; // "> "
319	    let li = (row.saturating_sub(area.y)) as usize;
320	    let li = li.min(state.lines.len().saturating_sub(1));
321	    let rel_col = (col.saturating_sub(area.x)) as usize;
322	    let ci = rel_col.saturating_sub(prefix_w);
323	    let line_len = state.lines[li].chars().count();
324	    (li, ci.min(line_len))
325	}
