327	pub fn render_input(
328	    f: &mut Frame,
329	    state: &InputState,
330	    area: ratatui::layout::Rect,
331	    focused: bool,
332	    input_rect_out: &mut ratatui::layout::Rect,
333	) {
334	    let border_style = if focused {
335	        Style::default().fg(Color::Cyan)
336	    } else {
337	        Style::default().fg(Color::DarkGray)
338	    };
339	
340	    let block = Block::default()
341	        .borders(Borders::ALL)
342	        .border_type(BorderType::Rounded)
343	        .border_style(border_style);
344	
345	    let inner = block.inner(area);
346	    *input_rect_out = inner; // store for mouse click mapping
347	    f.render_widget(block, area);
348	
349	    let text_lines: Vec<Line> = state
350	        .lines
351	        .iter()
352	        .enumerate()
353	        .map(|(li, line)| {
354	            let mut spans = Vec::new();
355	
356	            // "> " prefix on first line, "  " on subsequent
357	            let prefix = if li == 0 { "> " } else { "  " };
358	            spans.push(Span::styled(prefix, Style::default().fg(Color::DarkGray)));
359	
360	            let chars: Vec<char> = line.chars().collect();
361	            for (ci, &ch) in chars.iter().enumerate() {
362	                let is_cursor = li == state.cursor_line && ci == state.cursor_col;
363	                let in_sel = in_selection(state, li, ci);
364	                let style = if is_cursor || in_sel {
365	                    Style::default().bg(Color::White).fg(Color::Black)
366	                } else {
367	                    Style::default().fg(Color::White)
368	                };
369	                spans.push(Span::styled(ch.to_string(), style));
370	            }
371	            // Cursor at end of line
372	            if li == state.cursor_line && state.cursor_col == chars.len() {
373	                spans.push(Span::styled(" ", Style::default().bg(Color::White).fg(Color::Black)));
374	            }
375	            Line::from(spans)
376	        })
377	        .collect();
378	
379	    let para = Paragraph::new(text_lines);
380	    f.render_widget(para, inner);
381	}
