383	fn in_selection(state: &InputState, li: usize, ci: usize) -> bool {
384	    let Some(sel) = &state.selection else { return false };
385	    let (sl, sc, el, ec) = if (sel.start_line, sel.start_col) < (sel.end_line, sel.end_col) {
386	        (sel.start_line, sel.start_col, sel.end_line, sel.end_col)
387	    } else {
388	        (sel.end_line, sel.end_col, sel.start_line, sel.start_col)
389	    };
390	    if li < sl || li > el { false }
391	    else if li == sl && li == el { ci >= sc && ci < ec }
392	    else if li == sl { ci >= sc }
393	    else if li == el { ci < ec }
394	    else { true }
395	}
