397	/// Advance one position in the text (col+1, or next line start).
398	fn advance_pos(lines: &[String], li: usize, ci: usize) -> (usize, usize) {
399	    let line_len = lines[li].chars().count();
400	    if ci < line_len { (li, ci + 1) }
401	    else if li + 1 < lines.len() { (li + 1, 0) }
402	    else { (li, ci) }
403	}
