75	async fn run_loop(
76	    terminal: &mut Terminal<CrosstermBackend<io::Stdout>>,
77	    state: &mut AppState,
78	) -> Result<()> {
79	    let settings = clui_config::Settings::from_env();
80	    let (event_tx, mut event_rx) = mpsc::channel::<AppEvent>(256);
81	
82	    // Spawn agent for initial tab (uses claude CLI subprocess, no API key needed)
83	    {
84	        let tx = agent_task::spawn_agent(
85	            state.tabs[0].id.clone(),
86	            state.cwd.to_string_lossy().to_string(),
87	            settings.default_model.clone(),
88	            event_tx.clone(),
89	        );
90	        if let TabKind::Chat { agent_tx } = &mut state.tabs[0].kind {
91	            *agent_tx = Some(tx);
92	        }
93	    }
94	
95	    // Initial git refresh
96	    let _ = event_tx.send(AppEvent::GitRefresh).await;
97	
